"use client";

import { useRef } from "react";
import { useKeypress } from "@/hooks/use-keypress";
import {
	InputGroup,
	InputGroupAddon,
	InputGroupInput,
} from "@/components/ui/input-group";
import { Kbd, KbdGroup } from "@/components/ui/kbd";
import { useSidebar } from "@/components/ui/sidebar";

export function AppSearch() {
	const groupRef = useRef<HTMLDivElement>(null);
	const { setOpen } = useSidebar();

	useKeypress({
		combo: ["meta+k", "ctrl+k"],
		callback: () => {
			const input = groupRef.current?.querySelector<HTMLInputElement>(
				"[data-slot=input-group-control]"
			);
			input?.focus({ preventScroll: true });
			setOpen(true);
		},
	});

	return (
		<InputGroup ref={groupRef}>
			<InputGroupAddon align="inline-start" className="pl-1.75">
				<IconPlaceholder
					hugeicons="SearchIcon"
					lucide="SearchIcon"
					phosphor="MagnifyingGlassIcon"
					remixicon="RiSearchLine"
					tabler="IconSearch"
				/>
			</InputGroupAddon>
			<InputGroupInput
				aria-label="Search"
				name="q"
				placeholder="Search..."
				type="search"
			/>
			<InputGroupAddon align="inline-end">
				<KbdGroup>
					<Kbd>⌘</Kbd>
					<Kbd>K</Kbd>
				</KbdGroup>
			</InputGroupAddon>
		</InputGroup>
	);
}

"use client";
import { cn } from "@/lib/utils";
import { useIsMobile } from "@/hooks/use-mobile";
import { SidebarTrigger, useSidebar } from "@/components/ui/sidebar";

type Place = "sidebar" | "navbar";

export function CustomTrigger({ place }: { place: Place }) {
	const isMobile = useIsMobile();
	const { open, openMobile } = useSidebar();
	const sidebarOpen = isMobile ? openMobile : open;

	return (
		<SidebarTrigger
			className={cn(
				"transition-opacity duration-0 ease-out motion-reduce:transition-none",
				!sidebarOpen &&
					place === "navbar" &&
					"0fill-mode-forwards delay-100 duration-300",
				sidebarOpen && place === "navbar" && "pointer-events-none opacity-0",
				!sidebarOpen && place === "sidebar" && "pointer-events-none opacity-0"
			)}
		/>
	);
}

import { cn } from "@/lib/utils";
import { SidebarInset, SidebarProvider } from "@/components/ui/sidebar";
import { AppHeader } from "@/components/app-header";
