					className={cn(
						"flex flex-1 flex-col p-4 md:p-6",
						"mx-auto w-full max-w-(--app-wrapper-max-width)"
					)}
				>
					{children}
				</div>
			</SidebarInset>
		</SidebarProvider>
	);
}

"use client";

import { cn } from "@/lib/utils";
import { useState } from "react";
import { Button } from "@/components/ui/button";

const latestChange = {
	title: "Real-time funnels",
	description:
		"Build and analyze conversion funnels with live event streaming in real-time.",
	url: "#",
} as const;

export function LatestChange() {
	const [isOpen, setIsOpen] = useState(true);

	if (!isOpen) {
		return null;
	}

	return (
		<div
			className={cn(
				"rounded-lg group/latest-change z-20 size-full justify-center border bg-background"
			)}
		>
			<div className="relative flex size-full flex-col gap-1.5 overflow-hidden px-3 pt-4 pb-1">
				<p className="font-medium text-xs">{latestChange.title}</p>
				<span className="text-[10px] text-muted-foreground">
					{latestChange.description}
				</span>
				<Button
					asChild
					className="w-max px-0 font-light text-xs"
					size="sm"
					variant="link"
				>
					<a href={latestChange.url}>Read more</a>
				</Button>
				<Button
					className="absolute top-2 right-2 z-10 size-6 rounded-full opacity-0 transition-opacity group-hover/latest-change:opacity-100"
					onClick={() => setIsOpen(false)}
					size="icon-sm"
					variant="secondary"
				>
					<IconPlaceholder
						className="size-3.5 text-muted-foreground"
						hugeicons="Cancel01Icon"
						lucide="XIcon"
						phosphor="XIcon"
						remixicon="RiCloseLine"
						tabler="IconX"
					/>
				</Button>
			</div>
		</div>
	);
}

"use client";

import { useTheme } from "next-themes";
import * as React from "react";
import { Button } from "@/components/ui/button";

export function ThemeSwitcher() {
	const { setTheme, resolvedTheme } = useTheme();

	const toggleTheme = React.useCallback(() => {
		setTheme(resolvedTheme === "dark" ? "light" : "dark");
	}, [resolvedTheme, setTheme]);

	return (
		<Button
			className="text-muted-foreground"
			onClick={toggleTheme}
			size="icon-sm"
			variant="ghost"
		>
			<svg
				className="size-4.5"
				fill="none"
				height="24"
				stroke="currentColor"
				strokeLinecap="round"
				strokeLinejoin="round"
				strokeWidth="2"
				viewBox="0 0 24 24"
				width="24"
				xmlns="http://www.w3.org/2000/svg"
			>
				<path d="M0 0h24v24H0z" fill="none" stroke="none" />
				<path d="M12 12m-9 0a9 9 0 1 0 18 0a9 9 0 1 0 -18 0" />
				<path d="M12 3l0 18" />
				<path d="M12 9l4.65 -4.65" />
				<path d="M12 14.3l7.37 -7.37" />
				<path d="M12 19.6l8.85 -8.85" />
			</svg>
			<span className="sr-only">Toggle theme</span>
		</Button>
	);
}

"use client";

import { useCallback, useEffect, useMemo, useRef } from "react";

const MODS = ["ctrl", "alt", "shift", "meta"] as const;

const isMod = (p: string): boolean => (MODS as readonly string[]).includes(p);

const IGNORE_FOCUS = new Set(["INPUT", "TEXTAREA", "SELECT"]);

export type UseKeypressOptions = {
	/** One or more chords, e.g. `"meta+k"` or `["ctrl+b", "meta+b"]` — any match fires `callback`. */
	combo: string | string[];
	callback: (event: KeyboardEvent) => void;
	/** When true, calls `preventDefault()` if a chord matches. Default is true. */
	preventDefault?: boolean;
	/** Element to attach to; omit for `window`. */
	target?: HTMLElement | null;
};

function normalize(combo: string): string {
	const parts = combo
		.toLowerCase()
		.split("+")
		.map((s) => s.trim());
	const M = MODS as readonly string[];
	const mods = parts.filter(isMod).sort((a, b) => M.indexOf(a) - M.indexOf(b));
	const keys = parts.filter((p) => !isMod(p));
	return [...mods, ...keys].join("+");
}

function matches(e: KeyboardEvent, norm: string): boolean {
	const segs = norm.split("+");
	const wantMods = segs.filter(isMod);
	const wantKey = segs.find((p) => !isMod(p));
	const haveMods = [
		e.ctrlKey && "ctrl",
		e.altKey && "alt",
		e.shiftKey && "shift",
		e.metaKey && "meta",
	].filter(Boolean) as string[];

	if (
		wantMods.length !== haveMods.length ||
		!wantMods.every((m) => haveMods.includes(m))
	) {
		return false;
	}
	return e.key.toLowerCase() === wantKey;
}

/**
 * Listens for `keydown` shortcut chords. Skips firing while focus is in an input,
 * textarea, select, or `contentEditable` region.
 */
export function useKeypress({
	combo,
	callback,
	preventDefault = true,
	target,
}: UseKeypressOptions) {
	const callbackRef = useRef(callback);
	useEffect(() => {
		callbackRef.current = callback;
	}, [callback]);

	const normalized = useMemo(
		() => (Array.isArray(combo) ? combo : [combo]).map(normalize),
		[combo]
	);

	const onKeyDown = useCallback(
		(ev: Event) => {
			const e = ev as KeyboardEvent;
			const el = e.target as HTMLElement | undefined;
			if (IGNORE_FOCUS.has(el?.tagName ?? "") || el?.isContentEditable) {
				return;
			}
			for (const chord of normalized) {
				if (!matches(e, chord)) {
					continue;
				}
				if (preventDefault) {
					e.preventDefault();
				}
				callbackRef.current(e);
				break;
			}
		},
		[normalized, preventDefault]
	);

	useEffect(() => {
		const el = target ?? window;
		el.addEventListener("keydown", onKeyDown);
		return () => el.removeEventListener("keydown", onKeyDown);
	}, [onKeyDown, target]);
}
